208:                                         last_filter_in_filter_chain, filter_chain_type, stat_prefix,
209:                                         listener_filter_matcher),
210:         server_context_(server_context), factory_context_(factory_context) {}
211:   void validateMessage(const std::string& config_name, const Protobuf::Message& message,
212:                        const std::string& factory_name) const override {
213:     auto* factory =
214:         Registry::FactoryRegistry<NeutralHttpFilterConfigFactory>::getFactory(factory_name);
215:     const bool is_terminal_filter = factory->isTerminalFilterByProto(message, server_context_);
216:     Config::Utility::validateTerminalFilters(config_name, factory_name, filter_chain_type_,
217:                                              is_terminal_filter, last_filter_in_filter_chain_);
